SELECT
COALESCE(SUM(f.foodMaterialPrice * f.foodMaterialCount), 0)
FROM FOODM f
WHERE f.bId = #{bId}
AND f.incomeDate >= #{startDate}
AND f.incomeDate < #{endDate}

SELECT
COALESCE(
ROUND(
SUM(d.disposalCount) * 100 / NULLIF(SUM(f.foodMaterialCount), 0),
2
),
0
) AS disposalRate
FROM DISPOSALS d
JOIN FOODM f
ON d.foodMaterial_Id = f.foodMaterial_Id
WHERE f.bId = #{bId}
AND d.disposalDate >= #{startDate}
AND d.disposalDate < #{endDate}

SELECT
COALESCE(SUM(d.disposalPrice), 0)
FROM DISPOSALS d
JOIN FOODM f
ON d.foodMaterial_Id = f.foodMaterial_Id
WHERE f.bId = #{bId}
AND d.disposalDate >= #{startDate}
AND d.disposalDate < #{endDate}
